149	/// The request received by a [`Queryable`].
150	///
151	/// The `Query` provides all data sent by [`Querier::get`](crate::query::Querier::get)
152	/// or [`Session::get`](crate::Session::get): the key expression, the
153	/// parameters, the payload, and the attachment, if any.
154	///
155	/// The reply to the query should be made with one of its methods:
156	/// - [`Query::reply`](crate::query::Query::reply) to reply with a data [`Sample`](crate::sample::Sample) of kind [`Put`](crate::sample::SampleKind::Put),
157	/// - [`Query::reply_del`](crate::query::Query::reply_del) to reply with a data [`Sample`](crate::sample::Sample) of kind [`Delete`](crate::sample::SampleKind::Delete),
158	/// - [`Query::reply_err`](crate::query::Query::reply_err) to send an error reply.
159	///
160	/// The important detail: the [`Query::key_expr`] is **not** the key expression
161	/// which should be used as the parameter of [`reply`](Query::reply), because it may contain globs.
162	/// The [`Queryable`]'s key expression is the one that should be used.
163	///
164	/// This parameter is not set automatically because [`Queryable`](crate::query::Queryable) itself
165	/// may serve glob key expressions and send replies on different concrete key expressions
166	/// matching this glob. For example, a `Queryable` serving `foo/*` may receive a `Query`
167	/// with key expression `foo/bar` and another one with `foo/baz`, and it should reply
168	/// respectively on `foo/bar` and `foo/baz`.
169	#[derive(Clone)]
170	pub struct Query {
171	    pub(crate) inner: Arc<QueryInner>,
172	    pub(crate) eid: EntityId,
173	    pub(crate) value: Option<(ZBytes, Encoding)>,
174	    pub(crate) attachment: Option<ZBytes>,
175	}
