561	impl Query {
562	    pub(crate) fn _reply_sample(&self, sample: Sample) -> ZResult<()> {
563	        if !self._accepts_any_replies() && !self.key_expr().intersects(&sample.key_expr) {
564	            bail!("Attempted to reply on `{}`, which does not intersect with query `{}`, despite query only allowing replies on matching key expressions", sample.key_expr, self.key_expr())
565	        }
566	        #[cfg(not(feature = "unstable"))]
567	        let ext_sinfo = None;
568	        #[cfg(feature = "unstable")]
569	        let ext_sinfo = sample.source_info.map(Into::into);
570	        self.inner.primitives.send_response(&mut Response {
571	            rid: self.inner.qid,
572	            wire_expr: self.inner.primitives.keyexpr_to_wire(&sample.key_expr),
573	            payload: ResponseBody::Reply(zenoh::Reply {
574	                consolidation: zenoh::ConsolidationMode::DEFAULT,
575	                ext_unknown: vec![],
576	                payload: match sample.kind {
577	                    SampleKind::Put => ReplyBody::Put(Put {
578	                        timestamp: sample.timestamp,
579	                        encoding: sample.encoding.into(),
580	                        ext_sinfo,
581	                        #[cfg(feature = "shared-memory")]
582	                        ext_shm: None,
583	                        ext_attachment: sample.attachment.map(|a| a.into()),
584	                        ext_unknown: vec![],
585	                        payload: sample.payload.into(),
586	                    }),
587	                    SampleKind::Delete => ReplyBody::Del(Del {
588	                        timestamp: sample.timestamp,
589	                        ext_sinfo,
590	                        ext_attachment: sample.attachment.map(|a| a.into()),
591	                        ext_unknown: vec![],
592	                    }),
593	                },
594	            }),
595	            ext_qos: sample.qos.into(),
596	            ext_tstamp: None,
597	            ext_respid: Some(response::ext::ResponderIdType {
598	                zid: self.inner.zid,
599	                eid: self.eid,
600	            }),
601	        });
602	        Ok(())
603	    }
604	}
