670	
671	impl<Handler> Wait for QueryableUndeclaration<Handler> {
672	    fn wait(mut self) -> <Self as Resolvable>::To {
673	        self.queryable.undeclare_impl()?;
674	        if self.wait_callbacks {
675	            self.queryable.callback_sync_group.wait();
676	        }
677	        Ok(())
678	    }
679	}
680	
681	impl<Handler> IntoFuture for QueryableUndeclaration<Handler> {
682	    type Output = <Self as Resolvable>::To;
683	    type IntoFuture = Ready<<Self as Resolvable>::To>;
684	
685	    fn into_future(self) -> Self::IntoFuture {
686	        std::future::ready(self.wait())
687	    }
688	}
689	/// A `Queryable` is an entity that implements the query/reply pattern.
690	///
691	/// A `Queryable` is declared by the
692	/// [`Session::declare_queryable`](crate::Session::declare_queryable) method
693	/// and serves [`Query`](crate::query::Query) using callback
694	/// or channel (see [handlers](crate::handlers) module documentation for details).
695	///
696	/// The `Queryable` receives [`Query`](crate::query::Query) requests from
697	/// [`Querier::get`](crate::query::Querier::get) or from [`Session::get`](crate::Session::get)
698	/// and sends back replies with the methods of the [`Query`](crate::query::Query): [`reply`](crate::query::Query::reply),
699	/// [`reply_err`](crate::query::Query::reply_err) or [`reply_del`](crate::query::Query::reply_del).
700	///
701	/// # Examples
702	///
703	/// Using callback:
704	/// ```
705	/// # #[tokio::main]
706	/// # async fn main() {
707	/// use futures::prelude::*;
708	///
709	/// let session = zenoh::open(zenoh::Config::default()).await.unwrap();
710	/// let queryable = session
711	///     .declare_queryable("key/expression")
712	///     .callback(move |query| {
713	///         use crate::zenoh::Wait;
714	///         println!(">> Handling query '{}'", query.selector());
715	///         query.reply("key/expression", "value").wait().unwrap();
716	/// #       format!("{query}");
717	/// #       format!("{query:?}");
718	///     })
719	///     .await
720	///     .unwrap();
721	/// # format!("{queryable:?}");
722	/// # session.get("key/expression").await.unwrap();
723	/// # }
724	/// ```
725	///
726	/// Using channel handler:
727	/// ```no_run
728	/// # #[tokio::main]
729	/// # async fn main() {
730	///
731	/// let session = zenoh::open(zenoh::Config::default()).await.unwrap();
732	/// let queryable = session
733	///     .declare_queryable("key/expression")
734	///     .await
735	///     .unwrap();
736	/// while let Ok(query) = queryable.recv_async().await {
737	///     println!(">> Handling query '{}'", query.selector());
738	///     query.reply("key/expression", "value").await.unwrap();
739	/// }
740	/// // queryable is undeclared at the end of the scope
741	/// # }
742	/// ```
743	#[non_exhaustive]
744	pub struct Queryable<Handler> {
745	    pub(crate) inner: QueryableInner,
746	    pub(crate) handler: Handler,
747	    pub(crate) callback_sync_group: SyncGroup,
748	}
749	
750	impl<Handler> fmt::Debug for Queryable<Handler> {
751	    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
752	        f.debug_struct("Queryable")
753	            .field("inner", &self.inner)
754	            .field("handler", &"..")
755	            .field("callback_sync_group", &self.callback_sync_group)
756	            .finish()
757	    }
758	}
759	
760	impl<Handler> Queryable<Handler> {
761	    /// Returns the [`EntityGlobalId`] of this Queryable.
762	    ///
763	    /// # Examples
764	    /// ```
765	    /// # #[tokio::main]
766	    /// # async fn main() {
767	    ///
768	    /// let session = zenoh::open(zenoh::Config::default()).await.unwrap();
769	    /// let queryable = session.declare_queryable("key/expression").await.unwrap();
770	    /// let queryable_id = queryable.id();
771	    /// # }
772	    /// ```
773	    #[zenoh_macros::unstable]
774	    pub fn id(&self) -> EntityGlobalId {
775	        EntityGlobalIdProto {
776	            zid: self.inner.session.zid().into(),
777	            eid: self.inner.id,
778	        }
779	        .into()
780	    }
781	
782	    /// Returns a reference to this queryable's handler.
783	    /// A handler is anything that implements [`IntoHandler`](crate::handlers::IntoHandler).
784	    /// The default handler is [`DefaultHandler`](crate::handlers::DefaultHandler).
785	    ///
786	    /// # Examples
787	    /// ```
788	    /// # #[tokio::main]
789	    /// # async fn main() {
790	    ///
791	    /// let session = zenoh::open(zenoh::Config::default()).await.unwrap();
792	    /// let queryable = session.declare_queryable("key/expression").await.unwrap();
793	    /// let handler = queryable.handler();
794	    /// # }
795	    /// ```
796	    pub fn handler(&self) -> &Handler {
797	        &self.handler
798	    }
799	
800	    /// Returns a mutable reference to this queryable's handler.
801	    /// A handler is anything that implements [`IntoHandler`](crate::handlers::IntoHandler).
802	    /// The default handler is [`DefaultHandler`](crate::handlers::DefaultHandler).
803	    ///
804	    /// # Examples
805	    /// ```
806	    /// # #[tokio::main]
807	    /// # async fn main() {
808	    ///
809	    /// let session = zenoh::open(zenoh::Config::default()).await.unwrap();
810	    /// let mut queryable = session.declare_queryable("key/expression").await.unwrap();
811	    /// let handler = queryable.handler_mut();
812	    /// # }
813	    /// ```
814	    pub fn handler_mut(&mut self) -> &mut Handler {
815	        &mut self.handler
816	    }
817	
818	    /// Undeclare the [`Queryable`].
819	    ///
820	    /// # Examples
821	    /// ```
822	    /// # #[tokio::main]
823	    /// # async fn main() {
824	    ///
825	    /// let session = zenoh::open(zenoh::Config::default()).await.unwrap();
826	    /// let queryable = session.declare_queryable("key/expression").await.unwrap();
827	    /// queryable.undeclare().await.unwrap();
828	    /// # }
829	    /// ```
830	    #[inline]
831	    pub fn undeclare(self) -> QueryableUndeclaration<Handler>
832	    where
833	        Handler: Send,
834	    {
835	        UndeclarableSealed::undeclare_inner(self, ())
836	    }
837	
838	    fn undeclare_impl(&mut self) -> ZResult<()> {
839	        // set the flag first to avoid double panic if this function panic
840	        self.inner.undeclare_on_drop = false;
841	        self.inner.session.close_queryable(self.inner.id)
842	    }
843	
844	    /// Make queryable run in background until the session is closed.
845	    ///
846	    /// # Examples
847	    /// ```
848	    /// # #[tokio::main]
849	    /// # async fn main() {
850	    ///
851	    /// let session = zenoh::open(zenoh::Config::default()).await.unwrap();
852	    /// let mut queryable = session.declare_queryable("key/expression").await.unwrap();
853	    /// queryable.set_background(true);
854	    /// # }
855	    /// ```
856	    #[zenoh_macros::internal]
857	    pub fn set_background(&mut self, background: bool) {
858	        self.inner.undeclare_on_drop = !background;
859	    }
860	
861	    /// Returns the [`KeyExpr`] this queryable responds to.
862	    ///
863	    /// # Examples
864	    /// ```
865	    /// # #[tokio::main]
866	    /// # async fn main() {
867	    ///
868	    /// let session = zenoh::open(zenoh::Config::default()).await.unwrap();
869	    /// let queryable = session.declare_queryable("key/expression")
870	    ///     .await
871	    ///     .unwrap();
872	    /// let key_expr = queryable.key_expr();
873	    /// # }
874	    /// ```
875	    #[inline]
876	    pub fn key_expr(&self) -> &KeyExpr<'static> {
877	        &self.inner.key_expr
878	    }
879	}
880	
881	impl<Handler> Drop for Queryable<Handler> {
882	    fn drop(&mut self) {
883	        if self.inner.undeclare_on_drop {
884	            if let Err(error) = self.undeclare_impl() {
885	                error!(error);
886	            }
887	        }
888	    }
889	}
890	
891	impl<Handler: Send> UndeclarableSealed<()> for Queryable<Handler> {
892	    type Undeclaration = QueryableUndeclaration<Handler>;
893	
894	    fn undeclare_inner(self, _: ()) -> Self::Undeclaration {
895	        QueryableUndeclaration {
896	            queryable: self,
897	            wait_callbacks: false,
898	        }
899	    }
900	}
901	
902	impl<Handler> Deref for Queryable<Handler> {
903	    type Target = Handler;
904	
905	    fn deref(&self) -> &Self::Target {
906	        self.handler()
907	    }
908	}
909	
910	impl<Handler> DerefMut for Queryable<Handler> {
911	    fn deref_mut(&mut self) -> &mut Self::Target {
912	        self.handler_mut()
913	    }
914	}
